import{_ as i,o as s,c as e,a2 as t}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"训练集、验证集、测试集与 Benchmark","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"dataset-splits-benchmarks","verified":"2026-07-17T00:00:00.000Z","tags":["ai","dataset","validation","test","benchmark"]},"headers":[],"relativePath":"04-ai/notes/00-foundations/dataset-splits-benchmarks.md","filePath":"04-ai/notes/00-foundations/dataset-splits-benchmarks.md","lastUpdated":null}'),l={name:"04-ai/notes/00-foundations/dataset-splits-benchmarks.md"};function n(r,a,h,o,p,d){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="训练集、验证集、测试集与-benchmark" tabindex="-1">训练集、验证集、测试集与 Benchmark <a class="header-anchor" href="#训练集、验证集、测试集与-benchmark" aria-label="Permalink to &quot;训练集、验证集、测试集与 Benchmark&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>训练集用于更新模型参数；验证集用于选择模型、Prompt、超参数和停止条件；测试集只用于对最终方案做相对独立的估计。Benchmark 是具有任务、数据、运行规则和评分方法的标准化评测，用于在约定条件下比较系统。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>如果开发者根据测试结果不断修改方案，测试集信息会进入决策，最终分数会高估真实泛化能力。公开 Benchmark 能提供外部参照，但通常不能覆盖具体产品的用户、数据、权限、成本和失败损失。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><ul><li>数据划分应避免同一文档、同一用户、近重复内容或时间上相关样例跨集合泄漏。</li><li>时间敏感任务常按时间切分，确保测试数据发生在训练/开发数据之后。</li><li>三个集合应接近目标线上分布；若分布不同，指标解释必须注明。</li><li>Benchmark 分数只有在相同数据版本、Prompt、工具、采样、运行次数和评分器下才可直接比较。</li><li>污染是模型训练数据包含测试题或答案，导致分数不能代表新任务能力。</li></ul><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>AI 应用可以采用：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>development.jsonl  # 日常 Prompt、RAG 和流程调试</span></span>
<span class="line"><span>regression.jsonl   # 已修复线上/实验失败，持续扩充</span></span>
<span class="line"><span>test.jsonl         # 版本发布前评估，限制查看与调参</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>每条样例记录 ID、来源、日期、许可、任务标签、输入、期望、评分器版本和风险等级。报告同时给出样例数量、分组分布、置信区间或多次 Trial 结果，不只给一个总分。</p><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>随机按行切分包含同一文档多个 Chunk 的数据，造成内容泄漏。</li><li>用公开 Benchmark 排名直接决定产品模型，不测真实输入和成本。</li><li>在测试失败后逐条修改 Prompt，再继续报告同一测试集分数。</li><li>测试集只有正常样例，没有无答案、权限、边界和对抗样例。</li><li>更换 Judge 模型或 Rubric 后直接与旧分数比较。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>离线评测无法替代线上监控。线上数据受真实流量、界面、延迟、用户行为和系统集成影响；发布后仍需观察任务完成、人工接管、投诉、安全和费用指标。</p><h2 id="数据流与泄漏边界" tabindex="-1">数据流与泄漏边界 <a class="header-anchor" href="#数据流与泄漏边界" aria-label="Permalink to &quot;数据流与泄漏边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;原始样例&quot;] --&gt; B[&quot;按用户、文档或时间分组&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;开发集：拟合与迭代&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; D[&quot;验证集：选择方案&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; E[&quot;测试集：发布前一次性判断&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; F[&quot;Prompt、模型或检索版本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; E</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>同一来源的近重复样例必须先分组再切分，否则一个文档的段落可能同时进入开发集和测试集。测试结果一旦被用于逐题修改方案，该集合就参与了开发，不再是独立测试集。</p><h2 id="指标与-benchmark-明细" tabindex="-1">指标与 Benchmark 明细 <a class="header-anchor" href="#指标与-benchmark-明细" aria-label="Permalink to &quot;指标与 Benchmark 明细&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>必须记录</th><th>主要边界</th></tr></thead><tbody><tr><td>数据版本</td><td>样例 ID、来源、许可、切分规则</td><td>更新参考答案后不可与旧分数直接混合</td></tr><tr><td>运行配置</td><td>模型完整标识、Prompt、工具、采样、Trial 数</td><td>模型别名移动会破坏复现</td></tr><tr><td>指标</td><td>公式、单位、宏/微平均、阈值</td><td>总平均会掩盖高风险分组</td></tr><tr><td>Benchmark</td><td>任务、数据、提交规则、评分器</td><td>排名不等于产品任务表现</td></tr><tr><td>污染检查</td><td>近重复、训练暴露、公开答案</td><td>只能降低风险，无法证明完全无污染</td></tr></tbody></table><h2 id="可计算示例" tabindex="-1">可计算示例 <a class="header-anchor" href="#可计算示例" aria-label="Permalink to &quot;可计算示例&quot;">​</a></h2><p>假设 20 个测试样例分为 normal 12 个、no-answer 4 个、permission 4 个。某方案分别通过 11、4、1 个，总通过率是 <code>16 / 20 = 80%</code>，但权限切片仅 <code>1 / 4 = 25%</code>。若发布门槛规定权限切片必须达到 100%，该方案不能发布。计算结果同时说明：总分不能替代分组门槛。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>对规范化文本、来源 ID 和父文档 ID做重复检查。</li><li>输出每个集合的标签、时间和来源分布，确认目标线上样例没有缺失。</li><li>冻结测试集访问权限；发布评估前保存配置哈希。</li><li>分数异常跃升时优先检查泄漏、参考答案变化、评分器版本和模型别名。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为 30 条样例设计分组切分。验收：说明分组键与理由；三个集合无父文档交叉；至少包含正常、无答案、权限和对抗切片；写出一个总体指标、两个分组门槛及测试集被查看后的处理规则。</p><h2 id="完整案例-构建客服意图评测集" tabindex="-1">完整案例：构建客服意图评测集 <a class="header-anchor" href="#完整案例-构建客服意图评测集" aria-label="Permalink to &quot;完整案例：构建客服意图评测集&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>240 条经授权和脱敏的客服请求，字段为 <code>case_id</code>、<code>account_hash</code>、<code>created_at</code>、<code>intent</code>、<code>text</code>。</li><li>同一账户可能在同一工单内连续发送多条消息。</li><li>产品发布门槛：总体准确率至少 85%，<code>cancel-order</code> 召回率至少 95%，权限越界回答为 0。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>先按 <code>account_hash + case_id</code> 聚合，避免同一工单的近重复消息跨集合。</li><li>用最早 70% 时间段建立开发集，中间 15% 建立验证集，最新 15% 作为测试集。</li><li>开发集用于编写 Prompt 和错误分析；验证集用于选择 Prompt 与模型；测试集在候选版本冻结后运行一次。</li><li>为 <code>cancel-order</code>、无答案、权限不足、长文本分别生成切片统计。</li><li>保存数据哈希、切分脚本版本、模型完整 ID、Prompt 版本、Schema 版本和运行次数。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;dataset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;support-intent-v3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;split_rule&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group-by-account-case_then_time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;test&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;count&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">36</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;accuracy&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.861</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;slices&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;cancel_order_recall&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.917</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;permission_violations&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>总体准确率通过，但取消订单召回率低于 95%，因此结论是“不发布”。不能删除失败样例或临时降低门槛后宣布通过。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>断言一个 <code>case_id</code> 只属于一个集合。</li><li>人工抽查规范化后相似度最高的跨集合样例，确认没有模板复制。</li><li>用固定输出重新运行评分器，结果必须一致。</li><li>对三次模型 Trial 分别保存结果，再报告均值和最差值。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若发布后团队根据这 36 条测试样例逐题修改 Prompt，该测试集转为开发证据。应建立新的冻结测试集，并在报告中保留旧测试集已暴露的事实，不能继续把旧分数解释为独立泛化估计。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>实体泄漏：同一用户、工单、文档或模板的派生样例不得跨集合。</li><li>时间泄漏：预测未来时不能让未来事件、后验标签或更新后的文档进入开发输入。</li><li>标签泄漏：输入字段不能直接或间接包含参考答案。</li><li>评测泄漏：根据测试失败逐题修改后，测试集必须重新定性为开发证据。</li><li>评分器漂移：Rubric、Judge 或阈值变化必须产生新评分版本。</li><li>样本量：小切片需同时报告分子、分母，不能只给百分比。</li><li>Trial：随机输出保存每次运行，不选择最好一次。</li><li>缺失切片：线上重要语言、权限和无答案场景必须进入数据设计。</li><li>污染：公开 Benchmark 的高分不证明题目未进入训练数据。</li><li>发布：高损失切片门槛优先于总体平均。</li><li>复现：保存数据、代码、Prompt、模型和工具版本。</li><li>线上：离线通过后继续观察任务完成与人工接管。</li></ol><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://developers.google.com/machine-learning/crash-course/overfitting" target="_blank" rel="noreferrer">Google ML：Datasets, Generalization and Overfitting</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/glossary/" target="_blank" rel="noreferrer">Google ML Glossary</a>（访问日期：2026-07-17）</li><li><a href="https://platform.openai.com/docs/api-reference/evals" target="_blank" rel="noreferrer">OpenAI API：Evals</a>（访问日期：2026-07-17）</li><li><a href="https://www.anthropic.com/engineering/demystifying-evals-for-ai-agents" target="_blank" rel="noreferrer">Anthropic：Demystifying evals for AI agents</a>（访问日期：2026-07-17）</li></ul>`,43)])])}const u=i(l,[["render",n]]);export{k as __pageData,u as default};
